#include <bits/stdc++.h>
using namespace std;
const int N=85;
struct Number{
	int len,val[102];
	void clear(){
		len=0;
		memset(val,0,sizeof(val));
	}
	void Put(int x){
		clear();
		int tmp=x;
		while(tmp)
			val[++len]=tmp%10,tmp/=10;
	}
	//len=0时num=0;
}f[N][N],ans;
Number Time(Number res,int x){
	Number tmp;
	tmp.clear();
	tmp.len=res.len;
	for(int i=1;i<=tmp.len;i++)
		tmp.val[i]+=res.val[i]*x,tmp.val[i+1]+=tmp.val[i]/10,tmp.val[i]%=10;
	while(tmp.val[tmp.len+1])
		tmp.len++,tmp.val[tmp.len+1]+=tmp.val[tmp.len]/10,tmp.val[tmp.len]%=10;
	return tmp;
}
Number Plus(Number res,int x){
	Number tmp;
	tmp.clear();
	if(x)
		tmp.len=max(res.len,1);
	else
		tmp.len=res.len;
	for(int i=1;i<=tmp.len;i++)
		tmp.val[i]+=res.val[i]+x%10,tmp.val[i+1]+=tmp.val[i]/10,tmp.val[i]%=10,x/=10;
	while(tmp.val[tmp.len+1])
		tmp.len++,tmp.val[tmp.len+1]+=tmp.val[tmp.len]/10,tmp.val[tmp.len]%=10;
	return tmp;
}
Number cmp(Number num1,Number num2){
	if(num1.len>num2.len)
		return num1;
	if(num1.len<num2.len)
		return num2;
	for(int i=num1.len;i;i--){
		if(num1.val[i]>num2.val[i])
			return num1;
		if(num2.val[i]>num1.val[i])
			return num2;
	}
	return num1;
}
void output(Number res){
	if(res.len==0){
		puts("0");
		return;
	}
	for(int i=res.len;i;i--)
		printf("%d",res.val[i]);
	puts("");
}
Number BPlus(Number res1,Number res2){
	Number tmp;
	tmp.clear();
	tmp.len=max(res1.len,res2.len);
	for(int i=1;i<=tmp.len;i++)
		tmp.val[i]+=res1.val[i]+res2.val[i],tmp.val[i+1]+=tmp.val[i]/10,tmp.val[i]%=10;
	if(tmp.val[tmp.len+1])
		tmp.len++;
	return tmp;
}
int n,m,a[N];
int main(){
	ans.clear();
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++)
			 scanf("%d",&a[j]);
		for(int l=1;l<=m;l++)
			for(int r=l;r<=m;r++){
				if(l==r)
					f[l][r].Put(a[l]*2);
				else
					f[l][r].clear();
			}
		for(int len=2;len<=m;len++)
			for(int l=1;l+len-1<=m;l++){
				int r=l+len-1;
				f[l][r]=cmp(Plus(Time(f[l][r-1],2),a[r]*2),Plus(Time(f[l+1][r],2),a[l]*2));
			}
		ans=BPlus(ans,f[1][m]);
	}
	output(ans);
	return 0;
}
